// build-store-blueprint — Validate Upstream Inputs
// Checks all required Phase 6 artifacts are present before LLM synthesis.
// CLOUD MODE: all data arrives inline via n8n pipeline.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const strategySynthesis  = input.strategy_synthesis;
const offerArchitecture  = input.offer_architecture;
const contentStrategy    = input.content_strategy;
const gtmPlan            = input.gtm_plan;
const runtimeConfig      = input.runtime_config;
const projectId          = input.project_id;

if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

if (!strategySynthesis || !strategySynthesis.growth_thesis) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis.growth_thesis is required. Run build-strategy-synthesis first.');
}
if (!offerArchitecture || !offerArchitecture.core_offer || !offerArchitecture.core_offer.headline) {
  throw new Error('MISSING_ARTIFACT: offer_architecture.core_offer.headline is required. Run build-offer-architecture first.');
}
if (!contentStrategy || !contentStrategy.messaging_hierarchy || !contentStrategy.messaging_hierarchy.primary_message) {
  throw new Error('MISSING_ARTIFACT: content_strategy.messaging_hierarchy.primary_message is required. Run build-content-strategy first.');
}
if (!gtmPlan || !gtmPlan.gtm_narrative) {
  throw new Error('MISSING_ARTIFACT: gtm_plan.gtm_narrative is required. Run build-gtm-plan first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

console.log('build-store-blueprint: inputs validated. cloud=' + cloudMode + ' project=' + projectId);

return [{
  json: {
    project_id:           projectId,
    runtime_config:       runtimeConfig,
    strategy_synthesis:   strategySynthesis,
    offer_architecture:   offerArchitecture,
    content_strategy:     contentStrategy,
    gtm_plan:             gtmPlan,
    cloud_mode:           cloudMode,
  },
}];

// build-store-blueprint — Build LLM Synthesis Prompt
// Assembles the LLM prompt from upstream artifacts.

const input = $input.first().json;
const ss  = input.strategy_synthesis;
const oa  = input.offer_architecture;
const cs  = input.content_strategy;
const gp  = input.gtm_plan;
const rc  = input.runtime_config;

// Context assembly
const growthThesis     = ss.growth_thesis || '';
const positionFocus    = (typeof ss.positioning_focus === 'object') ? (ss.positioning_focus.primary_angle || JSON.stringify(ss.positioning_focus)) : (ss.positioning_focus || '');
const offerHeadline    = (oa.core_offer || {}).headline || '';
const targetBuyer      = (oa.core_offer || {}).target_buyer || '';
const pricingTier      = (oa.pricing_logic || {}).tier || '';
const bundleCount      = (oa.bundle_opportunities || []).length;
const primaryMessage   = (cs.messaging_hierarchy || {}).primary_message || '';
const contentPillars   = (cs.content_pillars || []).map(function(p) { return p.pillar || ''; }).join(', ');
const seoKeywords      = ((cs.seo_content_plan || {}).primary_keyword_clusters || []).map(function(k) { return k.cluster || k; }).join(', ');
const gtmNarrative     = gp.gtm_narrative || '';
const channels         = (gp.channel_strategy || []).map(function(c) { return c.channel || c; }).join(', ');

var lines = [];
lines.push('You are a Shopify store architect. Your task is to produce a detailed, structured store blueprint for a Shopify store.');
lines.push('');
lines.push('The blueprint must be pure planning output — no Shopify API calls, no live data. This is the architectural plan from which the store will be built.');
lines.push('');
lines.push('## Strategic Context');
lines.push('Growth thesis: ' + growthThesis);
lines.push('Positioning focus: ' + positionFocus);
lines.push('Offer headline: ' + offerHeadline);
lines.push('Target buyer: ' + targetBuyer);
lines.push('Pricing tier: ' + pricingTier);
lines.push('Bundles planned: ' + bundleCount);
lines.push('Primary message: ' + primaryMessage);
lines.push('Content pillars: ' + contentPillars);
lines.push('SEO keyword clusters: ' + seoKeywords);
lines.push('GTM narrative: ' + gtmNarrative);
lines.push('Primary channels: ' + channels);
lines.push('');
lines.push('## Output Requirements');
lines.push('Return a JSON object that strictly matches this schema. Do NOT add any fields not listed.');
lines.push('');
lines.push('```json');
lines.push('{');
lines.push('  "products": [');
lines.push('    {');
lines.push('      "title": "string",');
lines.push('      "product_type": "string",');
lines.push('      "handle": "string (url-slug)",');
lines.push('      "description_hint": "string (1-2 sentence positioning note)",');
lines.push('      "price_range": "string (e.g. €29-€49)",');
lines.push('      "tags": ["string"],');
lines.push('      "collections": ["collection-handle"]');
lines.push('    }');
lines.push('  ],');
lines.push('  "collections": [');
lines.push('    {');
lines.push('      "handle": "string",');
lines.push('      "title": "string",');
lines.push('      "description": "string",');
lines.push('      "seo_rationale": "string",');
lines.push('      "sort_order": "best-selling|manual|created-desc|price-asc|price-desc|alpha-asc|alpha-desc"');
lines.push('    }');
lines.push('  ],');
lines.push('  "pages": [');
lines.push('    {');
lines.push('      "handle": "string",');
lines.push('      "title": "string",');
lines.push('      "purpose": "string",');
lines.push('      "content_direction": "string",');
lines.push('      "seo_focus": "string"');
lines.push('    }');
lines.push('  ],');
lines.push('  "navigation": [');
lines.push('    {');
lines.push('      "menu_handle": "main-menu|footer-menu",');
lines.push('      "title": "string",');
lines.push('      "items": [');
lines.push('        {');
lines.push('          "label": "string",');
lines.push('          "link_type": "collection|page|product|blog|url|search",');
lines.push('          "target": "string (handle or url)"');
lines.push('        }');
lines.push('      ]');
lines.push('    }');
lines.push('  ],');
lines.push('  "theme_sections": [');
lines.push('    {');
lines.push('      "page": "homepage|collection|product|about|faq",');
lines.push('      "section_type": "string (e.g. hero, featured-collection, testimonials, rich-text, faq)",');
lines.push('      "order": 1,');
lines.push('      "heading_hint": "string",');
lines.push('      "content_hint": "string",');
lines.push('      "cta_label": "string",');
lines.push('      "cta_target": "string"');
lines.push('    }');
lines.push('  ],');
lines.push('  "assets": [');
lines.push('    {');
lines.push('      "asset_type": "logo|favicon|hero-image|collection-banner|product-image|icon|background|other",');
lines.push('      "purpose": "string",');
lines.push('      "dimensions": "string (e.g. 1920x600)",');
lines.push('      "notes": "string"');
lines.push('    }');
lines.push('  ],');
lines.push('  "blueprint_narrative": "string (2-3 sentence executive summary)",');
lines.push('  "open_questions": ["string"]');
lines.push('}');
lines.push('```');
lines.push('');
lines.push('## Rules');
lines.push('- products: include 3-6 representative products that reflect the offer architecture and pricing tier');
lines.push('- collections: include 2-4 collections that serve SEO and merchandising goals');
lines.push('- pages: include at minimum about, faq, contact');
lines.push('- navigation: include main-menu and footer-menu');
lines.push('- theme_sections: include at minimum 4 homepage sections (hero, featured-collection, value-prop, trust/social-proof)');
lines.push('- assets: include at minimum logo, favicon, hero-image');
lines.push('- All handles must be lowercase-hyphenated slugs');
lines.push('- sort_order must be one of the allowed enum values');
lines.push('- link_type must be one of the allowed enum values');
lines.push('- asset_type must be one of the allowed enum values');
lines.push('- Return ONLY the JSON object, no markdown fences, no commentary');

const prompt = lines.join('\n');
return [{ json: { llm_prompt: prompt, project_id: input.project_id, runtime_config: input.runtime_config, cloud_mode: input.cloud_mode } }];

// build-store-blueprint — Parse Validate Write
// Parses LLM output, validates structure, returns artifact inline (cloud mode).
// Cloud mode: inline return. Self-hosted: disk write.

function buildRunId() {
  var ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  var rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

// LLM output arrives as $input; prompt context comes from the prompt builder node
const llmOutput = $input.first().json;
const upstream  = $node['Build LLM Synthesis Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId     = upstream.project_id;
const runtimeConfig = upstream.runtime_config;
const executionTs   = new Date().toISOString();
const runId         = buildRunId();

// ── Step 1: Parse LLM response ────────────────────────────────────────────
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

var blueprint;
try {
  var cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  var parsed = JSON.parse(cleaned);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    blueprint = parsed;
  } else {
    throw new Error('LLM returned non-object JSON: ' + typeof parsed);
  }
} catch (e) {
  throw new Error('PARSE_ERROR: LLM output is not valid JSON. ' + e.message + ' | Raw (200): ' + rawText.slice(0, 200));
}

// ── Step 2: Validation ────────────────────────────────────────────────────

var requiredArrays = ['products', 'collections', 'pages', 'navigation', 'theme_sections', 'assets'];
for (var i = 0; i < requiredArrays.length; i++) {
  var key = requiredArrays[i];
  if (!Array.isArray(blueprint[key])) {
    throw new Error('SCHEMA_VIOLATION: ' + key + ' must be an array. Got: ' + typeof blueprint[key]);
  }
}

if (blueprint.products.length < 1) {
  throw new Error('SCHEMA_VIOLATION: products must have at least 1 item.');
}
for (var p = 0; p < blueprint.products.length; p++) {
  var prod = blueprint.products[p];
  if (!prod.title)        throw new Error('SCHEMA_VIOLATION: products[' + p + '].title is required.');
  if (!prod.product_type) throw new Error('SCHEMA_VIOLATION: products[' + p + '].product_type is required.');
}

if (blueprint.collections.length < 1) {
  throw new Error('SCHEMA_VIOLATION: collections must have at least 1 item.');
}
var VALID_SORT_ORDERS = ['best-selling', 'manual', 'created-desc', 'price-asc', 'price-desc', 'alpha-asc', 'alpha-desc'];
for (var c = 0; c < blueprint.collections.length; c++) {
  var coll = blueprint.collections[c];
  if (!coll.handle) throw new Error('SCHEMA_VIOLATION: collections[' + c + '].handle is required.');
  if (!coll.title)  throw new Error('SCHEMA_VIOLATION: collections[' + c + '].title is required.');
  if (coll.sort_order && !VALID_SORT_ORDERS.includes(coll.sort_order)) {
    console.warn('Auto-correcting collections[' + c + '].sort_order to best-selling');
    coll.sort_order = 'best-selling';
  }
}

var VALID_LINK_TYPES = ['collection', 'page', 'product', 'blog', 'url', 'search'];
for (var pg = 0; pg < blueprint.pages.length; pg++) {
  var page = blueprint.pages[pg];
  if (!page.handle)  throw new Error('SCHEMA_VIOLATION: pages[' + pg + '].handle is required.');
  if (!page.title)   throw new Error('SCHEMA_VIOLATION: pages[' + pg + '].title is required.');
  if (!page.purpose) throw new Error('SCHEMA_VIOLATION: pages[' + pg + '].purpose is required.');
}

for (var n = 0; n < blueprint.navigation.length; n++) {
  var nav = blueprint.navigation[n];
  if (!nav.menu_handle) throw new Error('SCHEMA_VIOLATION: navigation[' + n + '].menu_handle is required.');
  if (!nav.title)       throw new Error('SCHEMA_VIOLATION: navigation[' + n + '].title is required.');
  if (!Array.isArray(nav.items)) throw new Error('SCHEMA_VIOLATION: navigation[' + n + '].items must be an array.');
  for (var ni = 0; ni < nav.items.length; ni++) {
    var item = nav.items[ni];
    if (item.link_type && !VALID_LINK_TYPES.includes(item.link_type)) {
      console.warn('Auto-correcting nav item link_type "' + item.link_type + '" to url');
      item.link_type = 'url';
    }
  }
}

if (blueprint.theme_sections.length < 1) {
  throw new Error('SCHEMA_VIOLATION: theme_sections must have at least 1 item.');
}
for (var ts = 0; ts < blueprint.theme_sections.length; ts++) {
  var section = blueprint.theme_sections[ts];
  if (!section.page)         throw new Error('SCHEMA_VIOLATION: theme_sections[' + ts + '].page is required.');
  if (!section.section_type) throw new Error('SCHEMA_VIOLATION: theme_sections[' + ts + '].section_type is required.');
  if (typeof section.order !== 'number') { section.order = ts + 1; }
}

var VALID_ASSET_TYPES = ['logo', 'favicon', 'hero-image', 'collection-banner', 'product-image', 'icon', 'background', 'other'];
for (var a = 0; a < blueprint.assets.length; a++) {
  var asset = blueprint.assets[a];
  if (!asset.asset_type) throw new Error('SCHEMA_VIOLATION: assets[' + a + '].asset_type is required.');
  if (!VALID_ASSET_TYPES.includes(asset.asset_type)) {
    console.warn('Auto-correcting assets[' + a + '].asset_type to other');
    asset.asset_type = 'other';
  }
  if (!asset.purpose) throw new Error('SCHEMA_VIOLATION: assets[' + a + '].purpose is required.');
}

if (blueprint.blueprint_narrative && typeof blueprint.blueprint_narrative !== 'string') {
  blueprint.blueprint_narrative = String(blueprint.blueprint_narrative);
}

// Strip extra fields
var ALLOWED_KEYS = ['products', 'collections', 'pages', 'navigation', 'theme_sections', 'assets', 'blueprint_narrative', 'open_questions'];
var extraKeys = Object.keys(blueprint).filter(function(k) { return !ALLOWED_KEYS.includes(k); });
for (var ek = 0; ek < extraKeys.length; ek++) {
  delete blueprint[extraKeys[ek]];
}

// ── Step 3: Disk write (self-hosted only) ─────────────────────────────────
var cloudWarnings = [];
if (!cloudMode) {
  try {
    var fs   = require('fs');
    var path = require('path');
    var root = runtimeConfig.project_root || '/tmp/store-os/projects';
    var projectDir = path.join(root, projectId);
    if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });
    var outPath = path.join(projectDir, 'store-blueprint.json');
    fs.writeFileSync(outPath, JSON.stringify(blueprint, null, 2));
    console.log('Wrote store-blueprint.json to ' + outPath);
  } catch (writeErr) {
    cloudWarnings.push('Disk write failed: ' + writeErr.message);
  }
} else {
  cloudWarnings.push('Cloud mode: artifact returned inline, not written to disk.');
}

// ── Output summary ────────────────────────────────────────────────────────
var outputSummary = {
  products_count:       blueprint.products.length,
  collections_count:    blueprint.collections.length,
  pages_count:          blueprint.pages.length,
  navigation_menus:     blueprint.navigation.length,
  theme_sections_count: blueprint.theme_sections.length,
  assets_count:         blueprint.assets.length,
};

var envelope = {
  run_id:     runId,
  phase:      'store-blueprint',
  project_id: projectId,
  timestamp:  executionTs,
  cloud_mode: cloudMode,
  validation: { result: 'PASS', errors: [], warnings: cloudWarnings },
  diagnostics: { output_summary: outputSummary },
  lineage: {
    depends_on:  ['build-gtm-plan', 'build-content-strategy', 'build-offer-architecture', 'build-strategy-synthesis'],
    produced_by: 'build-store-blueprint',
  },
};

return [{
  json: {
    project_id:      projectId,
    artifact_name:   'store-blueprint',
    artifact_path:   null,
    store_blueprint: blueprint,
    runtime_config:  runtimeConfig,
    status:          'SUCCESS',
    cloud_mode:      cloudMode,
    cloud_warnings:  cloudWarnings,
    notes:           [],
    envelope:        envelope,
  },
}];
